const AWS = require('aws-sdk');
const https = require('https');
const http = require('http');
const { URL } = require('url');

const dynamoDb = new AWS.DynamoDB.DocumentClient();
const PAYMENT_API_URL = process.env.PAYMENT_API_URL;
const ORDERS_TABLE = process.env.ORDERS_TABLE;
const PAYMENT_TIMEOUT_MS = parseInt(process.env.PAYMENT_TIMEOUT_MS || '5000', 10);

function requestJson(method, urlString, body) {
  return new Promise((resolve, reject) => {
    try {
      const url = new URL(urlString);
      const payload = body ? JSON.stringify(body) : '';
      const isHttps = url.protocol === 'https:';
      const transport = isHttps ? https : http;

      const req = transport.request(
        {
          method,
          hostname: url.hostname,
          port: url.port || (isHttps ? 443 : 80),
          path: `${url.pathname}${url.search}`,
          headers: {
            'Content-Type': 'application/json',
            'Content-Length': Buffer.byteLength(payload)
          },
          timeout: PAYMENT_TIMEOUT_MS
        },
        (res) => {
          let data = '';
          res.on('data', (chunk) => {
            data += chunk;
          });
          res.on('end', () => {
            let parsed = null;
            try {
              parsed = data ? JSON.parse(data) : null;
            } catch (e) {
              parsed = data;
            }
            resolve({
              statusCode: res.statusCode,
              headers: res.headers,
              body: parsed
            });
          });
        }
      );

      req.on('timeout', () => {
        req.destroy(new Error('Payment API request timed out'));
      });

      req.on('error', reject);

      if (payload) req.write(payload);
      req.end();
    } catch (err) {
      reject(err);
    }
  });
}

async function processOrder(order) {
  const paymentResponse = await requestJson('POST', PAYMENT_API_URL, {
    orderId: order.orderId,
    amount: order.amount,
    currency: order.currency,
    customerId: order.customerId,
    paymentMethod: order.paymentMethod
  });

  const paymentStatus = paymentResponse.statusCode >= 200 && paymentResponse.statusCode < 300 ? 'PAID' : 'PAYMENT_FAILED';

  await dynamoDb
    .update({
      TableName: ORDERS_TABLE,
      Key: {
        orderId: order.orderId
      },
      UpdateExpression: 'SET #status = :status, updatedAt = :updatedAt, paymentResponse = :paymentResponse',
      ExpressionAttributeNames: {
        '#status': 'status'
      },
      ExpressionAttributeValues: {
        ':status': paymentStatus,
        ':updatedAt': new Date().toISOString(),
        ':paymentResponse': paymentResponse.body
      }
    })
    .promise();
}

exports.handler = async (event) => {
  const records = event.Records || [];

  await Promise.all(
    records.map(async (record) => {
      try {
        const order = JSON.parse(record.body);
        await processOrder(order);
      } catch (err) {
        console.error('Failed to process order record', {
          message: err && err.message ? err.message : err,
          recordId: record.messageId,
          body: record.body
        });
      }
    })
  );

  return {
    statusCode: 200,
    processed: records.length
  };
};